   810→
   811→  // Default to 1 week starting from current week (for detailed view)
   812→  const today = new Date();
   813→  const defaultFromDate = new Date(today);
   814→  defaultFromDate.setDate(today.getDate() - today.getDay()); // Start of week
   815→  const defaultToDate = new Date(defaultFromDate);
   816→  defaultToDate.setDate(defaultToDate.getDate() + 7); // 1 week ahead
   817→
   818→  let fromDate: Date;
