   857→  }
   858→
   859→  const pmResults = await db
   860→    .select({
   861→      pmId: pmSchedule.id,
   862→      trainId: pmSchedule.trainId,
   863→      trainNumber: trains.trainNumber,
   864→      fleetCode: fleets.code,
   865→      pmCode: pmTypes.pmCode,
   866→      pmName: pmTypes.pmName,
   867→      targetDate: pmSchedule.targetDate,
   868→      status: pmSchedule.status,
