   915→    ];
   916→
   917→    // Add update entry if updatedAt differs from createdAt
   918→    if (row.updatedAt && row.createdAt && row.updatedAt.getTime() !== row.createdAt.getTime()) {
   919→      changeHistory.push({
   920→        id: `${row.pmId}-update`,
   921→        timestamp: row.updatedAt.toISOString(),
   922→        changeType: 'MOVE',
   923→        userId: 'system',
   924→        userName: 'System',
   925→        reason: 'PM updated',
   926→      });
   927→    }
   928→
   929→    // Calculate constraint validation
   930→    const today = new Date();
   931→    today.setHours(0, 0, 0, 0);
   932→    const constraintEnd = new Date(row.constraintEnd);
   933→    const daysToDeadline = Math.floor((constraintEnd.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
   934→
   935→    const violations: Array<{
