  1071→
  1072→  const latestAnalysisResult = await db
  1073→    .select({ analysisDate: driftAnalysis.analysisDate })
  1074→    .from(driftAnalysis)
  1075→    .where(eq(driftAnalysis.baselineId, baseline.id))
