/**
 * GET /canvas/manhour-overlay
 *
 * Get man-hour overlay data showing depot workload by week.
 * Used to visualize resource utilization in the canvas sidebar.
 *
 * Query Parameters:
 * - depotId: Filter by depot (UUID, optional)
 * - weeks: Number of weeks to include (default: 12)
 */
canvasRoutes.get('/canvas/manhour-overlay', async (c) => {
  const requestId = getRequestId(c);

  const depotIdParam = c.req.query('depotId');
  const weeksParam = c.req.query('weeks');

  if (depotIdParam && !isValidUuid(depotIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid depot ID format', requestId),
      400
    );
  }

  const numWeeks = weeksParam ? parseInt(weeksParam, 10) : 12;
  if (isNaN(numWeeks) || numWeeks < 1 || numWeeks > 52) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Weeks must be between 1 and 52', requestId),
      400
    );
  }

  const latestRunResult = await db
    .select({ projectionRunId: manhourProjections.projectionRunId })
    .from(manhourProjections)
    .orderBy(desc(manhourProjections.createdAt))
    .limit(1);

  if (latestRunResult.length === 0) {
    return c.json(
      success(
        { weeks: [] },
        { timing: { durationMs: getRequestDuration(c) } }
      )
    );
  }

  const latestRunId = latestRunResult[0].projectionRunId;

  const conditions = [
    eq(manhourProjections.projectionRunId, latestRunId),
    eq(manhourProjections.granularity, 'WEEKLY'),
  ];

  if (depotIdParam) {
    conditions.push(eq(manhourProjections.depotId, depotIdParam));
  }

  const projections = await db
    .select({
      projectionId: manhourProjections.id,
      depotId: manhourProjections.depotId,
      depotCode: depots.code,
      periodStart: manhourProjections.periodStart,
      periodEnd: manhourProjections.periodEnd,
      requiredHours: manhourProjections.requiredTotalHours,
      availableHours: manhourProjections.availableTotalHours,
    })
    .from(manhourProjections)
    .innerJoin(depots, eq(manhourProjections.depotId, depots.id))
    .where(and(...conditions))
    .orderBy(manhourProjections.periodStart, depots.code)
    .limit(numWeeks * 10);

  const adjustmentsResult = await db
    .select({
      projectionId: manhourAdjustments.projectionId,
      adjustmentType: manhourAdjustments.adjustmentType,
      hoursAdjusted: manhourAdjustments.hoursAdjusted,
      status: manhourAdjustments.status,
    })
    .from(manhourAdjustments)
    .where(
      and(
        inArray(
          manhourAdjustments.projectionId,
          projections.map((p) => p.projectionId)
        ),
        eq(manhourAdjustments.status, 'PROPOSED')
      )
    );

  const adjustmentsByProjection = new Map<string, typeof adjustmentsResult>();
  for (const adj of adjustmentsResult) {
    if (!adjustmentsByProjection.has(adj.projectionId)) {
      adjustmentsByProjection.set(adj.projectionId, []);
    }
    adjustmentsByProjection.get(adj.projectionId)!.push(adj);
  }

  const weekMap = new Map<string, {
    weekStart: string;
    depots: Array<{
      depotId: string;
      depotCode: string;
      requiredHours: number;
      availableHours: number;
      utilizationPct: number;
      status: 'OVERLOADED' | 'OPTIMAL' | 'UNDERUTILIZED';
      adjustments: Array<{
        type: string;
        hours: number;
        status: string;
      }>;
    }>;
  }>();

  for (const proj of projections) {
    const weekStart = proj.periodStart;
    const required = parseFloat(proj.requiredHours);
    const available = parseFloat(proj.availableHours);
    const utilizationPct = available > 0 ? (required / available) * 100 : 0;

    let status: 'OVERLOADED' | 'OPTIMAL' | 'UNDERUTILIZED';
    if (required > available) {
      status = 'OVERLOADED';
    } else if (utilizationPct < 70) {
      status = 'UNDERUTILIZED';
    } else {
      status = 'OPTIMAL';
    }

    const adjustments = (adjustmentsByProjection.get(proj.projectionId) || []).map((a) => ({
      type: a.adjustmentType,
      hours: parseFloat(a.hoursAdjusted),
      status: a.status ?? 'PROPOSED',
    }));

    if (!weekMap.has(weekStart)) {
      weekMap.set(weekStart, { weekStart, depots: [] });
    }

    weekMap.get(weekStart)!.depots.push({
      depotId: proj.depotId,
      depotCode: proj.depotCode,
      requiredHours: Math.round(required * 10) / 10,
      availableHours: Math.round(available * 10) / 10,
      utilizationPct: Math.round(utilizationPct * 10) / 10,
      status,
      adjustments,
    });
  }

  const weeks = Array.from(weekMap.values()).sort(
    (a, b) => a.weekStart.localeCompare(b.weekStart)
  );

  return c.json(
    success(
      { weeks },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

